// Cloudflare Worker: Custom Caching Logic for API

// Constants for security and configuration
const MAX_TTL = 86400; // Maximum allowed TTL: 24 hours
const MIN_TTL = 60; // Minimum allowed TTL: 60 seconds
const DEFAULT_TTL = 300; // Default TTL: 5 minutes
const MAX_CACHE_KEY_LENGTH = 256;
const ALLOWED_ORIGINS = ['https://example.com', 'https://api.example.com'];
const ORIGIN_SERVER = 'https://origin.example.com';

// Allowed characters for cache key: alphanumeric, hyphens, underscores, dots, slashes
const CACHE_KEY_PATTERN = /^[a-zA-Z0-9\-_./]+$/;

addEventListener('fetch', (event) => {
  event.respondWith(handleRequest(event));
});

async function handleRequest(event) {
  const request = event.request;

  try {
    // Only allow GET and HEAD requests to be cached
    if (request.method !== 'GET' && request.method !== 'HEAD') {
      return fetchFromOrigin(request);
    }

    // Validate origin / CORS
    const origin = request.headers.get('Origin');
    if (origin && !isAllowedOrigin(origin)) {
      return new Response('Forbidden', { status: 403 });
    }

    const url = new URL(request.url);
    const params = url.searchParams;

    // Extract and validate cache parameters
    const rawTtl = params.get('ttl');
    const rawCacheKey = params.get('cache_key');

    const ttl = sanitizeTtl(rawTtl);
    const cacheKey = sanitizeCacheKey(rawCacheKey);

    // Remove cache control params from the URL forwarded to origin
    // to prevent cache poisoning via parameter manipulation
    const cleanUrl = buildCleanUrl(url);

    // Build the cache key URL
    const cacheKeyUrl = buildCacheKeyUrl(cleanUrl, cacheKey);

    // Use the Cache API
    const cache = caches.default;

    // Create a cache key request object
    const cacheKeyRequest = new Request(cacheKeyUrl, {
      method: 'GET',
      headers: request.headers,
    });

    // Attempt to find a cached response
    let response = await cache.match(cacheKeyRequest);

    if (response) {
      // Cache HIT
      const cachedResponse = new Response(response.body, response);
      cachedResponse.headers.set('X-Cache-Status', 'HIT');
      cachedResponse.headers.set('X-Cache-Key', cacheKeyUrl);
      setCorsHeaders(cachedResponse, origin);
      return cachedResponse;
    }

    // Cache MISS - fetch from origin
    const originRequest = buildOriginRequest(request, cleanUrl);
    response = await fetch(originRequest);

    // Only cache successful responses
    if (response.ok) {
      const responseToCache = new Response(response.body, response);

      // Set cache control headers based on validated TTL
      responseToCache.headers.set('Cache-Control', `public, max-age=${ttl}, s-maxage=${ttl}`);
      responseToCache.headers.delete('Set-Cookie'); // Never cache Set-Cookie headers

      // Remove any sensitive headers before caching
      sanitizeResponseHeaders(responseToCache);

      // Store in cache (non-blocking)
      event.waitUntil(cache.put(cacheKeyRequest, responseToCache.clone()));

      // Return response to client
      const clientResponse = new Response(responseToCache.body, responseToCache);
      clientResponse.headers.set('X-Cache-Status', 'MISS');
      clientResponse.headers.set('X-Cache-Key', cacheKeyUrl);
      clientResponse.headers.set('X-Cache-TTL', String(ttl));
      setCorsHeaders(clientResponse, origin);
      return clientResponse;
    }

    // Non-cacheable response (error, redirect, etc.)
    const passthrough = new Response(response.body, response);
    passthrough.headers.set('X-Cache-Status', 'BYPASS');
    setCorsHeaders(passthrough, origin);
    return passthrough;

  } catch (err) {
    // Log error but don't expose internals
    console.error('Worker error:', err.message);
    return new Response('Internal Server Error', {
      status: 502,
      headers: {
        'Content-Type': 'text/plain',
        'X-Cache-Status': 'ERROR',
      },
    });
  }
}

/**
 * Sanitize and validate TTL value
 */
function sanitizeTtl(rawTtl) {
  if (rawTtl === null || rawTtl === undefined) {
    return DEFAULT_TTL;
  }

  const parsed = parseInt(rawTtl, 10);

  if (isNaN(parsed) || !isFinite(parsed)) {
    return DEFAULT_TTL;
  }

  // Clamp to allowed range
  return Math.max(MIN_TTL, Math.min(MAX_TTL, parsed));
}

/**
 * Sanitize and validate cache key
 * Prevents cache poisoning and injection attacks
 */
function sanitizeCacheKey(rawCacheKey) {
  if (!rawCacheKey || typeof rawCacheKey !== 'string') {
    return null;
  }

  // Trim and enforce length limit
  const trimmed = rawCacheKey.trim().slice(0, MAX_CACHE_KEY_LENGTH);

  if (trimmed.length === 0) {
    return null;
  }

  // Validate against allowed pattern
  if (!CACHE_KEY_PATTERN.test(trimmed)) {
    console.warn(`Invalid cache key rejected: ${trimmed.slice(0, 50)}`);
    return null;
  }

  // Prevent path traversal
  if (trimmed.includes('..') || trimmed.includes('//')) {
    console.warn('Cache key with path traversal attempt rejected');
    return null;
  }

  return trimmed;
}

/**
 * Build a clean URL by removing cache control query parameters
 * This prevents cache poisoning via parameter manipulation
 */
function buildCleanUrl(url) {
  const clean = new URL(url.toString());
  clean.searchParams.delete('ttl');
  clean.searchParams.delete('cache_key');

  // Sort remaining parameters for consistent cache keys
  clean.searchParams.sort();

  return clean;
}

/**
 * Build the cache key URL
 * Uses a deterministic scheme to generate unique cache keys
 */
function buildCacheKeyUrl(cleanUrl, customCacheKey) {
  if (customCacheKey) {
    // Use custom cache key as a path prefix to namespace cached entries
    const cacheUrl = new URL(cleanUrl.toString());
    // Encode the custom key into the URL for cache API compatibility
    cacheUrl.pathname = `/cache-ns/${customCacheKey}${cacheUrl.pathname}`;
    return cacheUrl.toString();
  }

  // Default: use the clean URL as the cache key
  return cleanUrl.toString();
}

/**
 * Build the origin request, rewriting the URL to point to the origin server
 */
function buildOriginRequest(originalRequest, cleanUrl) {
  const originUrl = new URL(cleanUrl.toString());
  const origin = new URL(ORIGIN_SERVER);

  originUrl.protocol = origin.protocol;
  originUrl.hostname = origin.hostname;
  originUrl.port = origin.port;

  // Remove cache-ns prefix if present (shouldn't be, but safety check)
  originUrl.pathname = originUrl.pathname.replace(/^\/cache-ns\/[^/]+/, '');

  // Build new request with sanitized headers
  const headers = new Headers(originalRequest.headers);

  // Set proper Host header for origin
  headers.set('Host', origin.hostname);

  // Remove hop-by-hop headers
  headers.delete('cf-connecting-ip'); // Let Cloudflare re-add if needed
  headers.delete('cf-ray');

  // Add forwarding headers
  headers.set('X-Forwarded-For', originalRequest.headers.get('cf-connecting-ip') || '');
  headers.set('X-Forwarded-Proto', 'https');
  headers.set('X-Forwarded-Host', new URL(originalRequest.url).hostname);

  return new Request(originUrl.toString(), {
    method: originalRequest.method,
    headers: headers,
    redirect: 'manual', // Don't follow redirects automatically
  });
}

/**
 * Fetch directly from origin without caching (for non-GET methods)
 */
async function fetchFromOrigin(request) {
  const url = new URL(request.url);
  const originUrl = new URL(ORIGIN_SERVER);

  url.protocol = originUrl.protocol;
  url.hostname = originUrl.hostname;
  url.port = originUrl.port;

  const headers = new Headers(request.headers);
  headers.set('Host', originUrl.hostname);

  const originRequest = new Request(url.toString(), {
    method: request.method,
    headers: headers,
    body: request.body,
    redirect: 'manual',
  });

  const response = await fetch(originRequest);
  const newResponse = new Response(response.body, response);
  newResponse.headers.set('X-Cache-Status', 'BYPASS');
  newResponse.headers.set('Cache-Control', 'no-store');

  const origin = request.headers.get('Origin');
  setCorsHeaders(newResponse, origin);

  return newResponse;
}

/**
 * Remove sensitive headers from response before caching
 */
function sanitizeResponseHeaders(response) {
  // Remove headers that should never be cached
  const sensitiveHeaders = [
    'Set-Cookie',
    'Set-Cookie2',
    'Authorization',
    'WWW-Authenticate',
    'Proxy-Authenticate',
    'Proxy-Authorization',
  ];

  for (const header of sensitiveHeaders) {
    response.headers.delete(header);
  }

  // Add security headers
  response.headers.set('X-Content-Type-Options', 'nosniff');
  response.headers.set('X-Frame-Options', 'DENY');
  response.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin');
}

/**
 * Validate allowed origins
 */
function isAllowedOrigin(origin) {
  if (!origin) return true; // No origin header (same-origin or non-browser)
  return ALLOWED_ORIGINS.includes(origin);
}

/**
 * Set CORS headers on response
 */
function setCorsHeaders(response, origin) {
  if (origin && isAllowedOrigin(origin)) {
    response.headers.set('Access-Control-Allow-Origin', origin);
    response.headers.set('Access-Control-Allow-Methods', 'GET, HEAD, OPTIONS');
    response.headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    response.headers.set('Access-Control-Max-Age', '86400');
    response.headers.set('Vary', 'Origin');
  }
}